+{% load static %}
+{% load humanize %}
+{% load i18n %}
+{% language language %} {% get_current_language as LANGUAGE_CODE %}
+
+<!-- http://127.0.0.1:8000/openmap/en/#6c343726-1e92-451a-876a-76e17d398a1c 
+     https://github.com/Canadian-Geospatial-Platform/geoview/blob/develop/packages/geoview-core/public/templates/demos/demo-open-maps.html#L113 -->
+<!DOCTYPE html>
+<html class="no-js" lang="en" dir="ltr">
+<head>
+    <meta charset="utf-8">
+    <meta name="viewport" content="width=device-width,initial-scale=1" />
+    <title>Open Maps Data Viewer</title>
+    <meta content="width=device-width,initial-scale=1" name="viewport">
+    <meta property="dcterms:title" content="Open Maps Data Viewer" />
+    <meta name="msapplication-TileColor" content="#da532c" />
+    <meta name="msapplication-config" content="{% static 'ramp/geoviw/browserconfig.xml' %}"/>
+    <link href="{% static 'ramp/GCWeb/assets/favicon.ico' %}" rel="icon" type="image/x-icon">
+    <meta name="theme-color" content="#ffffff" />
+    <link href="https://fonts.googleapis.com/css?family=Roboto|Montserrat:200,300,400,900|Merriweather" rel="stylesheet" />
+    <link rel="stylesheet" href="https://fonts.googleapis.com/icon?family=Material+Icons" />
+    <link rel="stylesheet" href="{% static 'ramp/GCWeb/css/theme.css' %}">
+    <!-- script src="https://viewer-visualiseur.services.geo.ca/apps/GeoView/2.1.2/cgpv-main.js"></script -->
+    <!-- Analytics -->
+    {% if not DEBUG %}
+        {% include 'search_snippets/site_analytics_head.html' %}
+    {% endif %}
+    <noscript><link rel="stylesheet" href="{% static 'ramp/wet-boew/css/noscript.css' %}" /></noscript>
+</head>
+
+<body vocab="http://schema.org/" resource="#wb-webpage" typeof="WebPage">
+
+<script>
+    // Add click handlers to copy UUID to clipboard
+    document.querySelectorAll('.uuid-item').forEach((item) => {
+    item.addEventListener('click', function () {
+        // Extract UUID from the text (format: "number. UUID - description")
+        const text = this.textContent.trim();
+        const uuidMatch = text.match(/[a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12}/);
+
+        if (uuidMatch) {
+        const uuid = uuidMatch[0];
+        navigator.clipboard
+            .writeText(uuid)
+            .then(() => {
+            // Visual feedback
+            const originalBg = this.style.backgroundColor;
+            this.style.backgroundColor = '#4caf50';
+            setTimeout(() => {
+                this.style.backgroundColor = originalBg;
+            }, 200);
+            console.log('UUID copied to clipboard:', uuid);
+            })
+            .catch((err) => {
+            console.error('Failed to copy UUID:', err);
+            alert('Failed to copy UUID to clipboard');
+            });
+        }
+    });
+    });
+</script>    
+<nav>
+<ul id="wb-tphp">
+    <li class="wb-slc">
+        <a class="wb-sl" href="#wb-cont">{% translate "Skip to main content" %}</a>
+    </li>
+    <li class="wb-slc visible-sm visible-md visible-lg">
+        <a class="wb-sl" href="#wb-info">{% translate 'Skip to "About this site"' %}</a>
+    </li>
+</ul>
+</nav>
+
+<!-- WET Menu -->
+{% if language == 'fr' %}{% include 'snippets/wet_menu-fr.html' %}{% else %}{% include 'snippets/wet_menu-en.html' %}{% endif %}
+
+<main role="main" property="mainContentOfPage" class="container" style="width: auto!important;">
+    {% if show_alert_info %}
+    <section class="alert alert-danger" role="alert">
+      <p>{% translate 'Open Maps is undergoing maintenance. Certain features will be unavailable during this time. For questions or concerns, please <a href="https://open.canada.ca/en/forms/contact-us">contact us</a>.' %}</p>
+    </section>
+    {% endif %}
+
+    <section>
+        <h1 property="name" id="wb-cont" class="fgp-h1-top">{% translate 'Open Maps' %}</h1>
+        <ul>{% for id, title in titles.items %}
+            <li><a href="{{ open_data_url }}{{ id }}">{{ title | safe }}</a></li>
+        {% endfor %}
+        {% if language == 'fr' %}
+            {% if ramp_ga_resource_fr %}<li><a href="{{ ramp_ga_resource_fr }}" target="_blank">les données de mesure d'audience</a></li>{% endif %}
+        {% else %}
+            {% if ramp_ga_resource_en %}<li><a href="{{ ramp_ga_resource_en }}" target="_blank">Web analytics data</a></li>{% endif %}
+        {% endif %}
+        </ul>
+
+    {% if language == 'fr' %}
+    <!-- This is the div for the English version of the map -->
+    <div id="MapFR" class="geoview-map" data-lang="fr" data-config-url="{% static 'ramp/geoview/open-maps-config.json' %}"></div>
+    <!-- This is the div for the French version of the map -->    
+    {% else %}
+    
+    <div id="MapEN" class="geoview-map" data-lang="en" data-config-url="{% static 'ramp/geoview/open-maps-config.json' %}"></div>
+    {% endif %}
+    <div style="border-bottom: 3px solid #515ba5; margin: 20px 0"></div>
+
+    <!-- Link to Geoview, to replace by release hosted version https://viewer-visualiseur.services.geo.ca/apps/GeoView/2.1.2/cgpv-main.js -->
+    <script src="https://canadian-geospatial-platform.github.io/geoview/public/cgpv-main.js"></script> 
+
+    </section>
+</main>
+
+{% include 'snippets/wet_footer.html' %}
+
+<script src="https://code.jquery.com/jquery-2.2.4.min.js"
+        integrity="sha256-BbhdlvQf/xTY9gja0Dq3HiwQF8LaCRTXxZKRutelT44=" crossorigin="anonymous"></script>
+<script src="{% static 'ramp/wet-boew/js/wet-boew.js' %}"></script>
+<script src="{% static 'ramp/GCWeb/js/theme.min.js' %}"></script>
+
+
+<!-- Using Ramp configuration service so still need to use legacy API for now -->
+
+<script>
+      // JUST FOR DEMO
+      // insertPageHeader();
+
+      // Listen for hash changes to reload layers dynamically
+      window.addEventListener('hashchange', () => {
+        const newUuids = loadLayersFromHash();
+
+        if (newUuids) {
+          // Reload the page to clear old layers and load new ones
+          window.location.reload();
+        }
+      });
+
+      // ********** IMPORTANT CUSTOM CODE FOR KEYS INJECTION - START **********
+
+      // Function to load layers from UUID segment
+      function loadLayersFromHash() {
+        // Extract UUID(s) from URL hash (e.g., #uuid1,uuid2)
+        // Hash-based routing is used because GitHub Pages doesn't support server-side rewrites.
+        // Path-based routing (/demo-open-maps/uuid) only works with webpack dev server.
+        // const uuidSegment = window.location.hash.substring(1); // Remove # symbol
+        const uuidSegment = '{{ keys }}';
+
+        // If no hash, return empty array (map will init without layers)
+        if (!uuidSegment) {
+          return [];
+        }
+
+        // Split and validate each UUID using cgpv utilities
+        const uuids = uuidSegment.split(',').map((uuid) => uuid.trim());
+        const invalidUuids = [];
+
+        for (const uuid of uuids) {
+          if (!cgpv.api.utilities.core.isValidUUID(uuid)) {
+            invalidUuids.push(uuid);
+          }
+        }
+
+        if (invalidUuids.length > 0) {
+          alert(`Invalid UUID(s) found:\n${invalidUuids.join('\n')}\n\nPlease provide valid UUID(s) in the URL hash.`);
+          return false;
+        }
+
+        return uuids;
+      }
+
+      // Initial load
+      const initialUuids = loadLayersFromHash();
+
+      if (initialUuids !== false) {
+        // Proceed with map initialization
+        cgpv.onMapInit((mapViewer) => {
+          // Add layers only if UUIDs are provided
+          if (initialUuids.length > 0) {
+            initialUuids.forEach((uuid) => {
+              cgpv.api.getMapViewer(mapViewer.mapId).layer.addGeoviewLayerByGeoCoreUUID(uuid);
+            });
+          }
+        });
+
+        cgpv.init();
+      }
+
+      // ********** IMPORTANT CUSTOM CODE FOR KEYS INJECTION - END **********
+    </script>
+</body>
+</html>
+{% endlanguage %}

